import"./chunks/theme.Bv0bhO78.js";import{o as r,c as d,ae as a}from"./chunks/framework.PV3mkH3Y.js";const n=JSON.parse('{"title":"ตั้งค่าระบบ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/settings.md","filePath":"guide/settings.md"}'),o={name:"guide/settings.md"},h=Object.assign(o,{setup(s){return(l,t)=>(r(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="ตั้งค่าระบบ" tabindex="-1">ตั้งค่าระบบ <a class="header-anchor" href="#ตั้งค่าระบบ" aria-label="Permalink to &quot;ตั้งค่าระบบ&quot;">​</a></h1><p>ปรับแต่งระบบให้เหมาะกับการใช้งาน</p><div class="warning custom-block"><p class="custom-block-title">สิทธิ์การเข้าถึง</p><p>หน้าตั้งค่าส่วนใหญ่เข้าถึงได้เฉพาะ <strong>Admin</strong> และ <strong>Manager</strong> เท่านั้น</p></div><h2 id="เมนูตั้งค่า" tabindex="-1">เมนูตั้งค่า <a class="header-anchor" href="#เมนูตั้งค่า" aria-label="Permalink to &quot;เมนูตั้งค่า&quot;">​</a></h2><table tabindex="0"><thead><tr><th>เมนู</th><th>รายละเอียด</th><th>สิทธิ์</th></tr></thead><tbody><tr><td>จัดการลูกค้า</td><td>เพิ่ม แก้ไข ลบข้อมูลลูกค้า กำหนดชื่อ ที่อยู่ เบอร์โทร ส่วนลดประจำ</td><td>Admin, Manager</td></tr><tr><td>ประเภทงาน</td><td>กำหนดประเภทงานที่โรงงานรับผลิต เช่น กระจกนิรภัย กระจกเทมเปอร์</td><td>Admin, Manager</td></tr><tr><td>ตั้งค่าราคา</td><td>กำหนดราคาต่อหน่วยสำหรับแต่ละประเภทงานและวัสดุ</td><td>Admin, Manager</td></tr><tr><td>สติกเกอร์</td><td>ออกแบบ Template สติกเกอร์สำหรับติดบนชิ้นงาน</td><td>Admin, Manager</td></tr><tr><td>จัดการผู้ใช้งาน</td><td>เพิ่ม แก้ไข ลบบัญชีผู้ใช้ กำหนดสิทธิ์</td><td>Admin</td></tr><tr><td>การแจ้งเตือน</td><td>ตั้งค่าว่าต้องการรับแจ้งเตือนอะไรบ้าง</td><td>ทุกคน</td></tr><tr><td>การจัดการสิทธิ์และบทบาท</td><td>เพิ่ม เแก้ไข หรือลบบทบาท กำหนดสิทธิ์การเข้าถึงเมนูต่างๆ</td><td>Admin</td></tr></tbody></table><hr><h2 id="จัดการลูกค้า" tabindex="-1">จัดการลูกค้า <a class="header-anchor" href="#จัดการลูกค้า" aria-label="Permalink to &quot;จัดการลูกค้า&quot;">​</a></h2><p>เพิ่มและแก้ไขข้อมูลลูกค้าที่โรงงานให้บริการ</p><p><strong>ข้อมูลที่บันทึกได้:</strong></p><table tabindex="0"><thead><tr><th>ฟิลด์</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ชื่อลูกค้า</td><td>ชื่อบุคคลหรือบริษัท</td></tr><tr><td>ที่อยู่</td><td>ที่อยู่สำหรับจัดส่ง</td></tr><tr><td>เบอร์โทรศัพท์</td><td>เบอร์ติดต่อ</td></tr><tr><td>ส่วนลดประจำ (%)</td><td>ส่วนลดที่ให้กับลูกค้ารายนี้เสมอ</td></tr></tbody></table><details class="details custom-block"><summary>วิธีเพิ่มลูกค้าใหม่</summary><ol><li>เข้า <strong>ตั้งค่า</strong> → <strong>ลูกค้า</strong></li><li>กดปุ่ม <strong>+ เพิ่มลูกค้า</strong></li><li>กรอกข้อมูล: ชื่อ, ที่อยู่, เบอร์โทร, ส่วนลด</li><li>กด <strong>บันทึก</strong></li></ol></details><hr><h2 id="ประเภทงาน" tabindex="-1">ประเภทงาน <a class="header-anchor" href="#ประเภทงาน" aria-label="Permalink to &quot;ประเภทงาน&quot;">​</a></h2><p>กำหนดประเภทงานที่โรงงานรับผลิต ระบบนำไปใช้ในการคำนวณราคาและวางแผนการผลิต</p><p><strong>ข้อมูลที่บันทึกได้:</strong></p><table tabindex="0"><thead><tr><th>ฟิลด์</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ชื่อประเภทงาน</td><td>เช่น &quot;กระจกนิรภัย&quot;, &quot;กระจกลามิเนต&quot;</td></tr><tr><td>จำนวนกระจกดิบต่อชิ้น</td><td>กระจกดิบที่ต้องใช้ผลิต 1 ชิ้นงาน</td></tr></tbody></table><details class="details custom-block"><summary>วิธีเพิ่มประเภทงาน</summary><ol><li>เข้า <strong>ตั้งค่า</strong> → <strong>ประเภทงาน</strong></li><li>กดปุ่ม <strong>+ เพิ่มประเภทงาน</strong></li><li>กรอกชื่อและจำนวนกระจกดิบ</li><li>กด <strong>บันทึก</strong></li></ol></details><hr><h2 id="ตั้งค่าราคา" tabindex="-1">ตั้งค่าราคา <a class="header-anchor" href="#ตั้งค่าราคา" aria-label="Permalink to &quot;ตั้งค่าราคา&quot;">​</a></h2><p>กำหนดราคาขายต่อหน่วยสำหรับงานแต่ละประเภท ระบบนำไปคำนวณราคาในบิลอัตโนมัติ</p><p><strong>รูปแบบราคา:</strong></p><table tabindex="0"><thead><tr><th>ประเภทราคา</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ราคาต่อตารางเมตร</td><td>ราคาพื้นฐานคำนวณจากพื้นที่กระจก</td></tr><tr><td>บริการเพิ่มเติม</td><td>เช่น ขัดขอบ, เจาะรู, เจาะขอบ, ดัดโค้ง</td></tr></tbody></table><details class="details custom-block"><summary>วิธีกำหนดราคา</summary><ol><li>เข้า <strong>ตั้งค่า</strong> → <strong>ราคา</strong></li><li>เลือกประเภทงานที่ต้องการตั้งราคา</li><li>กรอกราคาต่อตารางเมตรและราคาบริการเสริม</li><li>กด <strong>บันทึก</strong></li></ol></details><hr><h2 id="ออกแบบสติกเกอร์" tabindex="-1">ออกแบบสติกเกอร์ <a class="header-anchor" href="#ออกแบบสติกเกอร์" aria-label="Permalink to &quot;ออกแบบสติกเกอร์&quot;">​</a></h2><p>สร้างและจัดการ Template สติกเกอร์สำหรับพิมพ์ติดชิ้นงาน</p><div class="tip custom-block"><p class="custom-block-title">ดูคู่มือเพิ่มเติม</p><p>คู่มือการออกแบบสติกเกอร์โดยละเอียดอยู่ที่ <a href="/guide/sticker-designer.html">ออกแบบสติกเกอร์</a></p></div><details class="details custom-block"><summary>วิธีสร้าง Template สติกเกอร์</summary><ol><li>เข้า <strong>ตั้งค่า</strong> → <strong>สติกเกอร์</strong></li><li>กดปุ่ม <strong>สร้าง Template ใหม่</strong> หรือเลือกแก้ไข Template ที่มีอยู่</li><li>ใช้เครื่องมือแก้ไขเพื่อเพิ่ม: ข้อความ, รูปภาพ, QR Code, ตัวแปรข้อมูล</li><li>กดบันทึก</li><li>สามารถนำไปพิมพ์ได้จากหน้าสถานีงาน</li></ol></details><hr><h2 id="จัดการผู้ใช้งานและบทบาท-roles" tabindex="-1">จัดการผู้ใช้งานและบทบาท (Roles) <a class="header-anchor" href="#จัดการผู้ใช้งานและบทบาท-roles" aria-label="Permalink to &quot;จัดการผู้ใช้งานและบทบาท (Roles)&quot;">​</a></h2><p>เพิ่ม แก้ไข หรือลบบัญชีผู้ใช้ และกำหนดสิทธิ์การเข้าถึงผ่านระบบบทบาท (Roles)</p><p><strong>ประเภทของบทบาท:</strong></p><table tabindex="0"><thead><tr><th>ประเภท</th><th>รายละเอียด</th></tr></thead><tbody><tr><td><strong>System Roles</strong></td><td><code>admin</code>, <code>manager</code>, <code>worker</code> เป็นบทบาทพื้นฐานของระบบที่ถูกกำหนดตายตัว ไม่สามารถลบหรือแก้ไขสิทธิ์ได้</td></tr><tr><td><strong>Custom Roles</strong></td><td>บทบาทที่คุณสามารถสร้างขึ้นเอง (เช่น &quot;หัวหน้าช่าง&quot;, &quot;เซลส์&quot;) และเลือกกำหนดสิทธิ์การเข้าถึงแต่ละเมนูได้อย่างอิสระ</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">เลือกระดับสิทธิ์ได้ตามต้องการ (RBAC)</p><p>เมื่อสร้างหรือแก้ไข <strong>Custom Role</strong> คุณจะมีรายชื่อเมนูทั้งหมดของระบบ (เช่น ดูคลังสินค้า, รับออเดอร์, จัดการการผลิต) เพื่อให้คุณเลือกติ๊ก <strong>&quot;เปิด/ปิด&quot;</strong> การเข้าถึงแต่ละส่วนได้ตามหน้าที่ของพนักงาน</p></div><details class="details custom-block"><summary>วิธีเพิ่มผู้ใช้งาน</summary><ol><li>เข้า <strong>ตั้งค่า</strong> → <strong>ผู้ใช้งานและบทบาท</strong> → เลือกแท็บ <strong>ผู้ใช้งาน</strong></li><li>กดปุ่ม <strong>เพิ่มผู้ใช้งาน</strong></li><li>กรอกข้อมูลและเลือกรหัสผ่าน</li><li>เลือกบทบาท (Role) ที่ต้องการมอบหมาย</li><li>กดบันทึก</li></ol></details><details class="details custom-block"><summary>วิธีสร้างบทบาทใหม่</summary><ol><li>เข้า <strong>ตั้งค่า</strong> → <strong>ผู้ใช้งานและบทบาท</strong> → เลือกแท็บ <strong>บทบาท</strong></li><li>กดปุ่ม <strong>เพิ่มบทบาท</strong></li><li>ตั้งชื่อบทบาทและเลือกสิทธิ์การเข้าถึงที่ต้องการให้มี</li><li>กดบันทึกเพื่อนำไปใช้กับพนักงานต่อไป</li></ol></details><hr><h2 id="การแจ้งเตือน" tabindex="-1">การแจ้งเตือน <a class="header-anchor" href="#การแจ้งเตือน" aria-label="Permalink to &quot;การแจ้งเตือน&quot;">​</a></h2><p>กำหนดการแจ้งเตือนที่ต้องการรับ</p><table tabindex="0"><thead><tr><th>การแจ้งเตือน</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>สต็อกต่ำ</td><td>แจ้งเตือนเมื่อวัสดุในคลังต่ำกว่าจุดสั่งซื้อ</td></tr><tr><td>ออเดอร์ใหม่</td><td>แจ้งเตือนเมื่อมีออเดอร์ใหม่เข้า</td></tr><tr><td>งานเสร็จ</td><td>แจ้งเตือนเมื่อชิ้นงานผ่านสถานีสุดท้าย</td></tr><tr><td>เสียง</td><td>เปิด/ปิดเสียงแจ้งเตือน</td></tr></tbody></table>',40)])]))}});export{n as __pageData,h as default};
